const group = new THREE.Group();

const steelMat = new THREE.MeshLambertMaterial({ color: '#6B7280' });
const holeMat = new THREE.MeshLambertMaterial({ color: '#1F2937' });

// Leaf dimensions
const leafW = 31 * mm;
const leafH = 63 * mm;
const leafT = 4 * mm;

// Left leaf plate (X: -31 to 0)
const leftGeo = new THREE.BoxGeometry(leafW, leafH, leafT);
const leftMesh = new THREE.Mesh(leftGeo, steelMat);
leftMesh.position.set(-leafW / 2, leafH / 2, leafT / 2);
group.add(leftMesh);

// Right leaf plate (X: 0 to +31)
const rightGeo = new THREE.BoxGeometry(leafW, leafH, leafT);
const rightMesh = new THREE.Mesh(rightGeo, steelMat);
rightMesh.position.set(leafW / 2, leafH / 2, leafT / 2);
group.add(rightMesh);

// Knuckles — 4 total, barrel along Y axis at X=0, Z=leaf_t+barrel_r=9.5mm
const barrelR = 5.5 * mm;
const knuckleLen = 15.45 * mm;
const knuckleGap = 0.4 * mm;
const barrelZ = leafT + barrelR;

for (let i = 0; i < 4; i++) {
  const yBottom = (63 * mm) - (i + 1) * knuckleLen - i * knuckleGap;
  const knuckleGeo = new THREE.CylinderGeometry(barrelR, barrelR, knuckleLen, 16);
  const knuckleMesh = new THREE.Mesh(knuckleGeo, steelMat);
  // CylinderGeometry default axis is Y — keep as-is, position at centre of knuckle
  knuckleMesh.position.set(0, yBottom + knuckleLen / 2, barrelZ);
  group.add(knuckleMesh);
}

// Mounting holes — 4 total: 2 per leaf, visual dark cylinders
const holeR = 3.25 * mm; // 6.5mm dia / 2
const holeYPositions = [11.5 * mm, 51.5 * mm];
const holeXPositions = [-20 * mm, 20 * mm];

for (const hy of holeYPositions) {
  for (const hx of holeXPositions) {
    const holeGeo = new THREE.CylinderGeometry(holeR, holeR, leafT + 0.5 * mm, 12);
    const holeMesh = new THREE.Mesh(holeGeo, holeMat);
    // Rotate hole to run along Z axis
    holeMesh.rotation.x = Math.PI / 2;
    holeMesh.position.set(hx, hy, leafT / 2);
    group.add(holeMesh);
  }
}

return group;
